}

function ProgressBar({
  value,
  max = 100,
  height = "h-4",
  label,
  className,
  ...props
}: ProgressBarProps) {
  const percent = Math.min(100, Math.max(0, (value / max) * 100))
  return (
    <div data-slot="progress-bar" className={cn("", className)} {...props}>
      <div className={cn("bg-surface-muted rounded-full overflow-hidden", height)}>
        <div
